/**
 * Delete a verification audit log entry
 */
export const deleteVerificationLogFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) =>
    deleteVerificationLogInputSchema.parse(data),
  )
  .handler(async ({ data }): Promise<{ success: boolean }> => {
    const db = getDb()

    const session = await getSessionFromCookie()
    if (!session?.userId) {
      throw new Error("Not authenticated")
    }

    await requireSubmissionReviewAccess(data.competitionId)

    getEvlog()?.set({
      action: "delete_verification_log",
      verification: { competitionId: data.competitionId, logId: data.logId },
    })

    // Verify the log entry belongs to this competition
    const [log] = await db
      .select({ id: scoreVerificationLogsTable.id })
      .from(scoreVerificationLogsTable)
      .where(
        and(
          eq(scoreVerificationLogsTable.id, data.logId),
          eq(scoreVerificationLogsTable.competitionId, data.competitionId),
        ),
      )
      .limit(1)

    if (!log) {
      throw new Error("Log entry not found")
    }

    await db
      .delete(scoreVerificationLogsTable)
      .where(eq(scoreVerificationLogsTable.id, data.logId))

    logInfo({
      message: "[Score] Organizer deleted verification log entry",
      attributes: {
        logId: data.logId,
        competitionId: data.competitionId,
        deletedByUserId: session.userId,
      },
    })

    return { success: true }
  })

/**
 * Update a verification audit log entry
 */
export const updateVerificationLogFn = createServerFn({ method: "POST" })
  .inputValidator((data: unknown) =>
    updateVerificationLogInputSchema.parse(data),
  )
  .handler(async ({ data }): Promise<{ success: boolean }> => {
    const db = getDb()

    const session = await getSessionFromCookie()
    if (!session?.userId) {
      throw new Error("Not authenticated")
    }

    await requireSubmissionReviewAccess(data.competitionId)

    getEvlog()?.set({
      action: "update_verification_log",
      verification: { competitionId: data.competitionId, logId: data.logId },
    })

    // Verify the log entry belongs to this competition and get scoreId + context
    const [log] = await db
      .select({
        id: scoreVerificationLogsTable.id,
        scoreId: scoreVerificationLogsTable.scoreId,
        trackWorkoutId: scoreVerificationLogsTable.trackWorkoutId,
        athleteUserId: scoreVerificationLogsTable.athleteUserId,
        penaltyType: scoreVerificationLogsTable.penaltyType,
      })
      .from(scoreVerificationLogsTable)
      .where(
        and(
          eq(scoreVerificationLogsTable.id, data.logId),
          eq(scoreVerificationLogsTable.competitionId, data.competitionId),
        ),
      )
      .limit(1)

    if (!log) {
      throw new Error("Log entry not found")
    }

    const logUpdates: Record<string, unknown> = {}
    if (data.action !== undefined) logUpdates.action = data.action
    if (data.penaltyType !== undefined)
      logUpdates.penaltyType = data.penaltyType
    if (data.penaltyPercentage !== undefined)
      logUpdates.penaltyPercentage = data.penaltyPercentage
    if (data.noRepCount !== undefined) logUpdates.noRepCount = data.noRepCount

    if (Object.keys(logUpdates).length === 0) {
      return { success: true }
    }

    // Check if penalty fields changed — need to sync to scoresTable
    const hasPenaltyChange =
      data.penaltyType !== undefined ||
      data.penaltyPercentage !== undefined ||
      data.noRepCount !== undefined

    // Detect penaltyType flip (null ↔ non-null) for review status update
    const oldPenaltyType = log.penaltyType
    const newPenaltyType =
      data.penaltyType !== undefined ? data.penaltyType : oldPenaltyType
    const penaltyTypeFlipped =
      data.penaltyType !== undefined &&
      Boolean(oldPenaltyType) !== Boolean(newPenaltyType)

    const now = new Date()

    await db.transaction(async (tx) => {
      // Update the log entry
      await tx
        .update(scoreVerificationLogsTable)
        .set(logUpdates)
        .where(eq(scoreVerificationLogsTable.id, data.logId))

      // Sync penalty fields to the denormalized scoresTable columns
      if (hasPenaltyChange) {
        const scoreUpdates: Record<string, unknown> = { updatedAt: now }
        if (data.penaltyType !== undefined)
          scoreUpdates.penaltyType = data.penaltyType
        if (data.penaltyPercentage !== undefined)
          scoreUpdates.penaltyPercentage = data.penaltyPercentage
        if (data.noRepCount !== undefined)
          scoreUpdates.noRepCount = data.noRepCount

        await tx
          .update(scoresTable)
          .set(scoreUpdates)
          .where(eq(scoresTable.id, log.scoreId))
      }

      // Update video submission reviewStatus when penaltyType flips
      if (penaltyTypeFlipped && log.trackWorkoutId) {
        const [registration] = await tx
          .select({ id: competitionRegistrationsTable.id })
          .from(competitionRegistrationsTable)
          .where(
            and(
              eq(competitionRegistrationsTable.eventId, data.competitionId),
              eq(competitionRegistrationsTable.userId, log.athleteUserId),
            ),
          )
          .limit(1)

        if (registration) {
          const videoReviewStatus = newPenaltyType ? "penalized" : "adjusted"
          await tx
            .update(videoSubmissionsTable)
            .set({
              reviewStatus: videoReviewStatus,
              statusUpdatedAt: now,
            })
            .where(
              and(
                eq(videoSubmissionsTable.registrationId, registration.id),
                eq(videoSubmissionsTable.trackWorkoutId, log.trackWorkoutId),
              ),
            )
        }
      }
    })

    logInfo({
      message: "[Score] Organizer updated verification log entry",
      attributes: {
        logId: data.logId,
        competitionId: data.competitionId,
        updatedByUserId: session.userId,
        updates: logUpdates,
      },
    })

    return { success: true }
  })

/**
 * Score formatting: converts Score objects to display strings
 */

import { decodeScore } from "../decode"
import type { FormatOptions, Score, ScoreRound, WorkoutScheme } from "../types"
import { formatStatus, isSpecialStatus } from "./status"

/**
 * Format a complete Score object for display.
 *
 * @param score - Score object to format
 * @param options - Format options
 *
 * @example
 * formatScore({ scheme: "time", scoreType: "min", value: 754567, status: "scored" })
 * // → "12:34.567"
 *
 * formatScore({
 *   scheme: "time-with-cap",
 *   scoreType: "min",
 *   value: null,
 *   status: "cap",
 *   timeCap: { ms: 900000, secondaryValue: 142 }
 * })
 * // → "CAP (142 reps)"
 *
 * formatScore({ scheme: "load", scoreType: "max", value: 102058, status: "scored" },
 *             { weightUnit: "lbs", includeUnit: true })
 * // → "225 lbs"
 */
export function formatScore(score: Score, options?: FormatOptions): string {
  const showStatus = options?.showStatus ?? true

  // Handle special statuses
  if (isSpecialStatus(score.status)) {
    return formatSpecialStatus(score, options, showStatus)
  }

  // Normal scored result
  if (score.value === null) {
    return "N/A"
  }

  return decodeScore(score.value, score.scheme, options)
}

/**
 * Format scores with special status (cap, dq, withdrawn).
 */
function formatSpecialStatus(
  score: Score,
  options?: FormatOptions,
  showStatus: boolean = true,
): string {
  const statusPrefix = showStatus ? formatStatus(score.status) : ""

  switch (score.status) {
    case "cap": {
      // Single-round capped: `timeCap.secondaryValue` holds reps at cap.
      if (score.timeCap?.secondaryValue !== undefined) {
        const repsFormatted = `${score.timeCap.secondaryValue} reps`
        return showStatus ? `${statusPrefix} (${repsFormatted})` : repsFormatted
      }
      // Multi-round capped: `value` is the summed total across rounds
      // (per-round caps enforced separately), so surface it.
      if (score.value !== null) {
        const decoded = decodeScore(score.value, score.scheme, options)
        return showStatus ? `${statusPrefix} (${decoded})` : decoded
      }
      return statusPrefix || "CAP"
    }

    case "dq":
      return statusPrefix || "DQ"

    case "withdrawn":
      return statusPrefix || "WD"

    default:

import {describe, expect, it} from 'vitest'

/**
 * Unit tests for competition leaderboard tie detection and ranking.
 *
 * These tests document the EXPECTED behavior for tie scenarios in competition rankings.
 * Currently, these tests FAIL because the implementation uses sequential ranking (i+1)
 * instead of proper tie-aware ranking.
 *
 * Expected behavior (Standard 1224 Ranking):
 * - Athletes with identical scores get the SAME rank
 * - Tied athletes receive the SAME points
 * - Next rank SKIPS appropriately (e.g., 1, 1, 3 not 1, 1, 2)
 *
 * Bug location: apps/wodsmith/src/server/competition-leaderboard.ts
 * - Event ranking: lines 372-383
 * - Overall ranking: lines 504-509
 */

/**
 * Helper function that implements the EXPECTED tie-aware ranking behavior.
 * This is the correct implementation that should replace the buggy sequential ranking.
 *
 * @param sortedScores - Array of scores already sorted by sortKey, secondaryValue, tiebreakValue
 * @returns Array of { rank, points } for each score
 */
function assignRanksWithTies<
  T extends {
    sortKey: string | null
    secondaryValue: number | null
    tiebreakValue: number | null
    status: string | null
  },
>(
  sortedScores: T[],
  athleteCount: number,
  calculatePointsFn: (rank: number, athleteCount: number) => number,
): Array<{rank: number; points: number}> {
  const results: Array<{rank: number; points: number}> = []
  let currentRank = 1

  for (let i = 0; i < sortedScores.length; i++) {
    const current = sortedScores[i]
    if (!current) continue

    // Check if this score ties with the previous score
    let isTied = false
    if (i > 0) {
      const prev = sortedScores[i - 1]
      if (prev) {
        // Two scores are equal when:
        // - sortKey matches
        // - secondaryValue matches (for capped scores)
        // - Either no tiebreak exists OR tiebreakValue matches
        const sortKeyMatch = current.sortKey === prev.sortKey
        const secondaryMatch = current.secondaryValue === prev.secondaryValue
        const tiebreakMatch =
          (current.tiebreakValue === null && prev.tiebreakValue === null) ||
          current.tiebreakValue === prev.tiebreakValue

        isTied = sortKeyMatch && secondaryMatch && tiebreakMatch
      }
    }

    // If not tied with previous, this is a new rank position
    if (!isTied) {
      currentRank = i + 1 // Skip ranks for previous ties
    }

    // Calculate points based on the rank (tied athletes get same points)
    const points = calculatePointsFn(currentRank, athleteCount)

    results.push({rank: currentRank, points})
  }

  return results
}

/**
 * calculatePoints function from competition-leaderboard.ts (lines 116-154)
 * Copied here for testing purposes.
 */
function calculatePoints(
  place: number,
  athleteCount: number,
  scoringType:
    | 'winner_takes_more'
    | 'even_spread'
    | 'fixed_step' = 'fixed_step',
  step = 5,
): number {
  switch (scoringType) {
    case 'winner_takes_more': {
      const basePoints = [
        100, 85, 75, 67, 60, 54, 49, 45, 41, 38, 35, 32, 30, 28, 26, 24, 22, 20,
        18, 16, 14, 12, 10, 8, 6, 4, 2, 1,
      ]
      if (place <= basePoints.length) {
        return basePoints[place - 1] ?? 1
      }
      return 1
    }

    case 'even_spread': {
      if (athleteCount <= 1) return 100
      const stepSize = 100 / (athleteCount - 1)
      return Math.max(0, Math.round(100 - (place - 1) * stepSize))
    }

    case 'fixed_step': {
      return Math.max(0, 100 - (place - 1) * step)
    }
  }
}

describe('calculatePoints', () => {
  describe('fixed_step scoring (default)', () => {
    it('should calculate points with default 5-point step', () => {
      expect(calculatePoints(1, 10)).toBe(100) // 1st place
      expect(calculatePoints(2, 10)).toBe(95) // 2nd place
      expect(calculatePoints(3, 10)).toBe(90) // 3rd place
      expect(calculatePoints(10, 10)).toBe(55) // 10th place
    })

    it('should not go below 0 points', () => {
      expect(calculatePoints(21, 10)).toBe(0) // 21st place would be -5
    })

    it('should support custom step sizes', () => {
      expect(calculatePoints(1, 10, 'fixed_step', 10)).toBe(100)
      expect(calculatePoints(2, 10, 'fixed_step', 10)).toBe(90)
      expect(calculatePoints(3, 10, 'fixed_step', 10)).toBe(80)
    })
  })

  describe('winner_takes_more scoring', () => {
    it('should give decreasing increments favoring winners', () => {
      expect(calculatePoints(1, 10, 'winner_takes_more')).toBe(100)
      expect(calculatePoints(2, 10, 'winner_takes_more')).toBe(85) // 15 point gap
      expect(calculatePoints(3, 10, 'winner_takes_more')).toBe(75) // 10 point gap
      expect(calculatePoints(4, 10, 'winner_takes_more')).toBe(67) // 8 point gap
    })

    it('should give 1 point for places beyond the array', () => {
      expect(calculatePoints(29, 30, 'winner_takes_more')).toBe(1)
      expect(calculatePoints(30, 30, 'winner_takes_more')).toBe(1)
    })
  })

  describe('even_spread scoring', () => {

/**
 * Sort key computation for database storage
 *
 * Sort keys encode status + normalized score into a single BigInt
 * for efficient single-column index sorting. Stored as a zero-padded
 * string in SQLite, so we are NOT limited to 64 bits.
 *
 * Structure (123-bit BigInt, stored as 38-char zero-padded string):
 * - Bits 122-120: status_order (0-7)
 * - Bits 119-80:  primary score value (40 bits, ~1 trillion max)
 * - Bits 79-40:   secondary value / inverted reps at cap (40 bits, ~1 trillion max)
 * - Bits 39-0:    tiebreak value (40 bits, ~1 trillion max)
 *
 * All three data segments use the same 40-bit width for simplicity.
 * Each handles any realistic score value with massive headroom.
 */

import { MAX_SCORE_VALUE, STATUS_ORDER } from "../constants"
import type { Score, ScoreStatus, SortDirection } from "../types"
import { getSortDirection } from "./direction"

/** Max value for each 40-bit segment (~1.1 trillion) */
const SEGMENT_MAX = 2n ** 40n - 1n

/** Bit positions for each segment */
const SECONDARY_SHIFT = 40n
const PRIMARY_SHIFT = 80n
const STATUS_SHIFT = 120n

/** Number of non-status bits */
const DATA_BITS = 120n

/**
 * Within the "cap" bucket we bit-pack `cappedRoundCount` into the top 8 bits
 * of the 40-bit primary segment so that a score with fewer capped rounds
 * always sorts ahead of a score with more, regardless of summed total.
 *
 * Time-with-cap values are milliseconds (32-bit safe for workouts up to ~49
 * days), so the low 32 bits of the primary slot hold the time and the next
 * 8 bits hold the capped-round count.
 */
const CAP_TIME_BITS = 32n
const CAP_TIME_MASK = (1n << CAP_TIME_BITS) - 1n
const CAP_COUNT_MAX = 255

/**
 * Compute a sort key for database storage.
 *
 * The sort key encodes status, score value, secondary value (reps at cap),
 * and tiebreak into a single integer for efficient index-based sorting.
 *
 * @param score - Score object or partial with required fields
 *
 * @example
 * // Time workout (lower is better)
 * computeSortKey({ value: 510000, status: "scored", scheme: "time", scoreType: "min" })
 * // → encodes status 0 + normalized value
 *
 * // Capped with secondary value
 * computeSortKey({ value: 600000, status: "cap", scheme: "time-with-cap", scoreType: "min",
 *   timeCap: { ms: 600000, secondaryValue: 100 } })
 * // → encodes status 1 + primary + inverted secondary (higher reps = lower key)
 */
export function computeSortKey(
  score: Pick<Score, "value" | "status" | "scheme" | "scoreType"> &
    Partial<
      Pick<Score, "timeCap" | "tiebreak" | "cappedRoundCount" | "rounds">
    >,
): bigint {
  const direction = getSortDirection(score.scheme, score.scoreType)

  // Extract secondary value (reps at cap) if present
  const secondaryValue = score.timeCap?.secondaryValue ?? 0

  // Derive capped-round count. Prefer the explicit field; otherwise fall
  // back to counting rounds with status "cap" when the full array is
  // available. This is the dominant tiebreaker inside the "cap" bucket.
  const cappedRoundCount =
    score.cappedRoundCount ??
    (score.rounds
      ? score.rounds.filter((r) => r.status === "cap").length
      : 0)

  // Extract tiebreak value if present
  // For time-based tiebreaks, lower is better (use as-is)
  // For reps-based tiebreaks, higher is better (invert)
  let tiebreakValue = 0n
  if (score.tiebreak) {
    const tbDirection = score.tiebreak.scheme === "time" ? "asc" : "desc"
    tiebreakValue =
      tbDirection === "asc"
        ? BigInt(score.tiebreak.value)
        : SEGMENT_MAX - BigInt(score.tiebreak.value)
  }

  return computeSortKeyWithComponents(
    score.value,
    score.status,
    direction,
    secondaryValue,
    tiebreakValue,
    cappedRoundCount,
  )
}

/**
 * Compute sort key with all components.
 *
 * @param value - Primary score value (null for incomplete)
 * @param status - Score status
 * @param direction - Sort direction for primary value
 * @param secondaryValue - Secondary value (reps at cap), higher is better
 * @param tiebreakValue - Pre-normalized tiebreak value
 * @param cappedRoundCount - Count of individual rounds marked "cap" (used
 *   as a dominant tiebreaker within the "cap" status bucket)
 */
function computeSortKeyWithComponents(
  value: number | null,
  status: ScoreStatus,
  direction: SortDirection,
  secondaryValue: number,
  tiebreakValue: bigint,
  cappedRoundCount: number = 0,
): bigint {
  const statusBits = BigInt(STATUS_ORDER[status]) << STATUS_SHIFT

  // Handle null values - they sort last within their status group
  if (value === null) {
    return statusBits | MAX_SCORE_VALUE
  }

  // Normalize primary value based on sort direction
  // For ascending (lower is better): use value as-is
  // For descending (higher is better): invert so higher values get lower sort keys
  let normalizedPrimary =
    direction === "asc"
      ? BigInt(value) & SEGMENT_MAX
      : SEGMENT_MAX - (BigInt(value) & SEGMENT_MAX)

  // Cap bucket: bit-pack `cappedRoundCount` above the time value so more
  // caps → larger primary → worse sort key, regardless of summed total.
  // Only meaningful for "asc" (time-with-cap is always asc) and only when
  // time fits in 32 bits (holds up to ~49 days of ms, far beyond any WOD).
  if (status === "cap" && direction === "asc" && cappedRoundCount > 0) {
    const clampedCount = Math.min(cappedRoundCount, CAP_COUNT_MAX)
    const timeBits = normalizedPrimary & CAP_TIME_MASK
    normalizedPrimary = (BigInt(clampedCount) << CAP_TIME_BITS) | timeBits
  }

  // For capped status, secondary value (reps) matters - higher is better, so invert
  // For scored status, secondary doesn't matter (use 0)
  const normalizedSecondary =
    status === "cap" ? SEGMENT_MAX - (BigInt(secondaryValue) & SEGMENT_MAX) : 0n

  // Combine: status | primary | secondary | tiebreak
  return (
    statusBits |
    (normalizedPrimary << PRIMARY_SHIFT) |
    (normalizedSecondary << SECONDARY_SHIFT) |
    (tiebreakValue & SEGMENT_MAX)
  )
}

/**
 * Compute sort key with explicit direction (legacy compatibility).
 *
 * @param value - Score value (null for incomplete)
 * @param status - Score status
 * @param direction - Sort direction
 */
export function computeSortKeyWithDirection(
  value: number | null,
  status: ScoreStatus,
  direction: SortDirection,
): bigint {
  return computeSortKeyWithComponents(value, status, direction, 0, 0n)
}

/**
 * Extract status and approximate value from a sort key.
 * Note: Value extraction is lossy — secondary and tiebreak bits are discarded.
 *
 * @param sortKey - The sort key to decode
 * @param direction - The sort direction used when encoding
 */
export function extractFromSortKey(
  sortKey: bigint,
  direction: SortDirection,
): {
  statusOrder: number
  value: number | null
} {
  // Extract status order from top bits
  const statusOrder = Number(sortKey >> STATUS_SHIFT)

  // Extract all non-status bits to check for null
  const allBits = sortKey & ((1n << DATA_BITS) - 1n)

  // Check for null (MAX_VALUE indicator)
  if (allBits === MAX_SCORE_VALUE) {
    return { statusOrder, value: null }
  }

  // Extract primary value from its segment
  const primaryBits = (sortKey >> PRIMARY_SHIFT) & SEGMENT_MAX

  // Strip any bit-packed cappedRoundCount so the returned value is the
  // original time (ms). Cap packing only happens on the ascending branch
  // in the "cap" status bucket.
  const timeBits =
    statusOrder === STATUS_ORDER.cap && direction === "asc"
      ? primaryBits & CAP_TIME_MASK
      : primaryBits

  // Denormalize the primary value
  const value =
    direction === "asc"
      ? Number(timeBits)
      : Number(SEGMENT_MAX - timeBits)

  return { statusOrder, value }
}

/**
 * Get the status from a status order number.
 */
export function statusFromOrder(order: number): ScoreStatus {
  const entries = Object.entries(STATUS_ORDER)
  for (const [status, statusOrder] of entries) {
    if (statusOrder === order) {
      return status as ScoreStatus
    }
  }
  return "scored"
}

/**
 * Convert a bigint sort key to a zero-padded string for database storage.
 *
 * Since SQLite stores sortKey as text, we need zero-padding to ensure
 * lexicographic string comparison produces the same ordering as numeric comparison.
 *
 * A 123-bit value can require up to 38 decimal digits (log10(2^123) ≈ 37.02),
 * so we pad to 38 characters to guarantee all possible values fit. In practice,
 * the highest status_order is 3 (withdrawn), so the current max is well under
 * 37 digits — but padding to 38 provides safety for the full 3-bit status range.
 *
 * @param sortKey - The bigint sort key to convert
 * @returns Zero-padded string representation
 *
 * @example
 * sortKeyToString(510000n) // → "00000000000000000000000000000000510000"
 */
export function sortKeyToString(sortKey: bigint): string {
  return sortKey.toString().padStart(38, "0")
}

