interface SubmissionStatusBadgeProps {
  status: ReviewStatus
  /** Optional timestamp for when the status was last updated */
  statusUpdatedAt?: Date | null
  /** Optional notes from the reviewer */
  reviewerNotes?: string | null
  /** Whether to show the tooltip (default: true) */
  showTooltip?: boolean
  /** Additional className for the badge */
  className?: string
  /** Size variant */
  size?: "sm" | "default"
}

function formatStatusDate(date: Date | string): string {
  const d = typeof date === "string" ? new Date(date) : date
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  }).format(d)
}

export function SubmissionStatusBadge({
  status,
  statusUpdatedAt,
  reviewerNotes,
  showTooltip = true,
  className,
  size = "default",
}: SubmissionStatusBadgeProps) {
  const config = statusConfig[status]
  const Icon = config.icon

  const badge = (
    <Badge
      variant="outline"
      className={cn(
        "gap-1.5 font-medium",
        config.className,
        size === "sm" && "px-2 py-0.5 text-[10px]",
        className,
      )}
    >
      <Icon
        className={cn(
          config.iconClassName,
          size === "sm" ? "h-3 w-3" : "h-3.5 w-3.5",
        )}
      />
      {config.label}
    </Badge>
  )

  if (!showTooltip) {
    return (
      <div className="space-y-1.5">
        {badge}
        {reviewerNotes && (
          <p className="text-xs italic text-muted-foreground">
            Organizer note: {reviewerNotes}
          </p>
        )}
      </div>
    )
  }

  return (
    <div className="space-y-1.5">
      <TooltipProvider>
        <Tooltip>
          <TooltipTrigger asChild>{badge}</TooltipTrigger>
          <TooltipContent className="max-w-xs space-y-2">
            <p>{config.description}</p>
            {statusUpdatedAt && (
              <p className="text-xs text-muted-foreground">
                Updated: {formatStatusDate(statusUpdatedAt)}
              </p>
            )}
          </TooltipContent>
        </Tooltip>
      </TooltipProvider>
      {reviewerNotes && (
        <p className="text-xs italic text-muted-foreground">
          Organizer note: {reviewerNotes}
        </p>
      )}
    </div>
  )
}

/**
 * Returns the status configuration for a given status.
 * Useful for displaying status info in other contexts.
 */
export function getStatusConfig(status: ReviewStatus): StatusConfig {
  return statusConfig[status]
}

